mapper.select:
/*
	평가 결과 조회2 (TB_LMS_DSCS_PTCP 단독 조회)
	ForumEzGraderDAO.selectEzgEvalRslt
*/
SELECT A.SCR   AS evalScore
	 , A.EVLYN AS evalYn
FROM TB_LMS_DSCS_PTCP A
WHERE A.USER_ID = #{evalTrgtUserId}
	AND A.DSCS_ID = #{dscsId}

mapper.insert:
/* 팀원 모두에게 점수 초기화2 ForumEzGraderDAO.initStdScoreToAllTeamMember -- MERGE 사용 사유(Upsert): 팀원별 기존 점수 존재 시 덮어쓰기, 없으면 신규 삽입 */ MERGE INTO TB_LMS_DSCS_PTCP T USING ( SELECT A.TEAM_ID , A.USER_ID , #{evalScore} AS SCR FROM TB_LMS_TEAM_MBR A WHERE A.TEAM_ID = #{rltnTeamCd}
AND A.USER_ID = #{evalTrgtUserId}
) S ON (T.DSCS_ID = #{dscsId} AND T.USER_ID = S.USER_ID) WHEN MATCHED THEN UPDATE SET SCR = S.SCR, MDFR_ID = #{rgtrId}, MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT (TEAM_ID, DSCS_ID, USER_ID, SCR, RGTR_ID, REG_DTTM, MDFR_ID, MOD_DTTM) VALUES (S.TEAM_ID, #{dscsId}, S.USER_ID, S.SCR, #{rgtrId}, FN_DTTM(), #{rgtrId}, FN_DTTM())

mapper.delete:
/*
	팀원 총 평가점수  삭제2
	ForumEzGraderDAO.deleteTeamStdScore
*/
DELETE FROM TB_LMS_DSCS_PTCP
WHERE TEAM_ID = #{rltnTeamCd}

	AND USER_ID = #{evalTrgtUserId}

mapper.insert:
/* 팀원 모두에게 총 평가점수 부여2 ForumEzGraderDAO.insertStdScoreToAllTeamMember -- MERGE 사용 사유(Upsert): 팀원별 기존 점수 존재 시 덮어쓰기, 없으면 신규 삽입 */ MERGE INTO TB_LMS_DSCS_PTCP T USING ( SELECT A.TEAM_ID, A.USER_ID FROM TB_LMS_TEAM_MBR A WHERE 1 = 1
AND TEAM_ID = #{rltnTeamCd} AND USER_ID = #{evalTrgtUserId}
AND TEAM_ID = #{rltnTeamCd}
) S ON (T.DSCS_ID = #{dscsId} AND T.USER_ID = S.USER_ID) WHEN MATCHED THEN UPDATE SET SCR = #{evalScore}, MDFR_ID = #{rgtrId}, MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT (TEAM_ID, DSCS_ID, USER_ID, SCR, RGTR_ID, REG_DTTM, MDFR_ID, MOD_DTTM) VALUES (S.TEAM_ID, #{dscsId}, S.USER_ID, #{evalScore}, #{rgtrId}, FN_DTTM(), #{rgtrId}, FN_DTTM())
